var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"여기는 힐데, 상황 종료했다.","JPN":"こちらヒルデ、状況終了を報告する。","ENG":"Hilde here. The situation has been contained.","TWN":"我是希爾德，戰鬥已結束。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"별다른 문제가 없으면 복귀하겠다.","JPN":"別途問題がなければ帰還する。","ENG":"Pending any further issues, we'll return to base.","TWN":"沒有其他問題的話，即將回歸。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"확인했습니다, 소대장님.","JPN":"了解しました、小隊長。","ENG":"Copy that, Commander.","TWN":"收到，小隊長。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"지금 복귀할 함선을 그쪽으로...... ","JPN":"直ちに帰還用の艦船をそちらへ…… ","ENG":"We'll send a ship to bring you back right now— ","TWN":"現在就派遣回歸艦船去接你……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"어라? 잠시만요......?","JPN":"あれ？　お待ちください……！","ENG":"Huh? Hang on...","TWN":"咦？等等……？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"이, 이상하네? 이게 왜 이러지?","JPN":"お、おかしいな。どうなっているの？","ENG":"Th-that's odd... What's going on?","TWN":"奇、奇怪？這是怎麼回事？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭐야? 무슨 일인데 그러나?","JPN":"なんだ？　説明を。","ENG":"What? What's wrong?","TWN":"怎麼了？什麼事？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"아. 죄송합니다, 소대장님. 그런데 침식파 반응이 아직 사라지지 않네요.","JPN":"申し訳ございません、小隊長。侵食波反応がまだ感知されているんです。","ENG":"Oh... Apologies, Commander. But I'm still picking up Corruption rays.","TWN":"啊，對不起，小隊長。侵蝕波反應還沒消除。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"3종 침식체는 전부 처리했는데, 근처에 남은 잔당들 아닌가?","JPN":"第3種侵食体は全部処理したが、周辺の残党の影響か？","ENG":"We've taken out all the Category 3's here. Isn't it from the other C.O.s?","TWN":"3類侵蝕體都已經處理了，應該是附近的一些小嘍嘍吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"아뇨. 침식파 밀도가 거의 3종 최상급입니다.","JPN":"いいえ。侵食波の密度がほぼ第3種最上級に達しています。","ENG":"No. The Corruption ray level suggests the presence of a top-notch Category 3.","TWN":"不，侵蝕波密度接近3類最頂級。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"......지금 발신 좌표가 갱신됐습니다.","JPN":"……発信座標が更新されました。","ENG":"The ray's coordinates of origin have been updated.","TWN":"……座標更新了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"북쪽 2Km 지점에서 펜릴 소대가 있는 곳을 향해 천천히 접근 중입니다.","JPN":"北方向2Km地点から、フェンリル小隊がいる地点に向かってゆっくりと接近中です。","ENG":"Tango slowly approaching Fenrir Squad, two klicks out from the north.","TWN":"正在從北邊2km地點向芬里爾小隊區域緩慢靠近。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......파티에 늦는 녀석들은 항상 있는 법이지.","JPN":"……宴に遅刻するやつは必ずいるものだ。","ENG":"Well, there's always someone who's late for the party.","TWN":"……派對總是有遲到的傢伙。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아무래도 연장근무가 조금 더 길어질 것 같군.","JPN":"どうやら残業がもう少し長引きそうだな。","ENG":"Looks like we'll have to pull extra overtime.","TWN":"看來加班時間要延長了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"오르카, 아직 작전이 끝난 게 아닌 것 같아.","JPN":"オルカ、まだ作戦が終わってないみたい。","ENG":"It seems like the mission isn't over yet, Orca.","TWN":"奧爾卡，作戰還沒有結束。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"그러니까 멋대로 침식체를 죽이겠다고 흥분하면 안 돼.","JPN":"だから侵食体を殺すってまた勝手に興奮しちゃダメよ。","ENG":"So don't go berserk on us, okay?","TWN":"所以，別因為要殺侵蝕體太興奮了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"네 안에 있는 오르카에게도 확실히 말해 두라고.","JPN":"あんたの中にいるオルカにもしっかり伝えてちょうだい。","ENG":"Make sure you tell the other Orca inside as well.","TWN":"也跟你身體裡的奧爾卡說一下。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};